# Watch-DistractingWindows.ps1
# Polls the active window title via Win32 API and fires a Windows toast
# notification + sound + minimize + cursor hijack whenever the title
# matches one of the predefined keywords.

# ─── Configuration ────────────────────────────────────────────────────────────

$Keywords = @(
    "messenger",
    "instagram",
    "facebook",
    "youtube",
    "invidious",
    "reddit",
    "whatsapp",
    "twitter",
	"tiktok"
)

$PollIntervalSeconds  = 1
$CooldownSeconds      = 20    # Per-keyword cooldown for sound + toast
$HijackGraceSeconds   = 10    # Global cooldown for minimize + cursor hijack
$AlertSoundRepeats    = 1

$AppId = "{1AC14E77-02E7-4E5D-B744-2EB1AE5198B7}\WindowsPowerShell\v1.0\powershell.exe"

# ─── Decode inline sound from end of this script ─────────────────────────────

$AlertSound = Join-Path $env:TEMP "distraction_alert.mp3"
$_selfContent = Get-Content -Raw $PSCommandPath
if ($_selfContent -match '(?s)#BEGIN_SOUND_BASE64\r?\n(.+?)\r?\n#END_SOUND_BASE64') {
    [IO.File]::WriteAllBytes($AlertSound, [Convert]::FromBase64String($Matches[1].Trim()))
    Write-Host "Sound decoded to: $AlertSound" -ForegroundColor DarkGray
} else {
    Write-Host "WARNING: No sound data found between markers - no sound will play." -ForegroundColor DarkYellow
}

# ─── Win32 + MCI API ──────────────────────────────────────────────────────────

Add-Type -AssemblyName System.Windows.Forms

Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
using System.Text;

public class WinApi {
    // ── Window title ──
    [DllImport("user32.dll")]
    public static extern IntPtr GetForegroundWindow();

    [DllImport("user32.dll", CharSet = CharSet.Auto, SetLastError = true)]
    public static extern int GetWindowText(IntPtr hWnd, StringBuilder lpString, int nMaxCount);

    [DllImport("user32.dll")]
    public static extern int GetWindowTextLength(IntPtr hWnd);

    // ── Minimize foreground window ──
    [DllImport("user32.dll")]
    public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);

    public const int SW_MINIMIZE = 6;

    // ── Cursor hijack ──
    [DllImport("user32.dll")]
    public static extern bool SetCursorPos(int x, int y);

    // ── MCI for MP3 playback (fire-and-forget) ──
    [DllImport("winmm.dll", CharSet = CharSet.Auto)]
    public static extern int mciSendString(string command, StringBuilder returnVal, int returnLength, IntPtr hwnd);

    public static void PlayAsync(string path) {
        string alias = "snd_alert";
        mciSendString("close "  + alias, null, 0, IntPtr.Zero);
        mciSendString("open \"" + path + "\" type mpegvideo alias " + alias, null, 0, IntPtr.Zero);
        mciSendString("play "   + alias, null, 0, IntPtr.Zero);
    }
}
'@

# ─── State ────────────────────────────────────────────────────────────────────

$LastNotified  = @{}
$LastHijack    = [datetime]::MinValue

# ─── Helpers ──────────────────────────────────────────────────────────────────

function Get-ActiveWindowTitle {
    $hwnd = [WinApi]::GetForegroundWindow()
    if ($hwnd -eq [IntPtr]::Zero) { return $null }

    $len = [WinApi]::GetWindowTextLength($hwnd)
    if ($len -le 0) { return $null }

    $sb = New-Object System.Text.StringBuilder ($len + 1)
    [WinApi]::GetWindowText($hwnd, $sb, $sb.Capacity) | Out-Null
    return $sb.ToString()
}

function Play-AlertSound {
    if (-not (Test-Path $AlertSound)) {
        Write-Host "  `[sound file not found: $AlertSound`]" -ForegroundColor DarkYellow
        return
    }
    try {
        for ($i = 0; $i -lt $AlertSoundRepeats; $i++) {
            [WinApi]::PlayAsync($AlertSound)
        }
        Write-Host "  `[sound fired async`]" -ForegroundColor Green
    } catch {
        Write-Host "  `[sound playback failed: $_`]" -ForegroundColor DarkYellow
    }
}

function Invoke-Hijack {
    $now     = [datetime]::UtcNow
    $elapsed = ($now - $script:LastHijack).TotalSeconds

    if ($elapsed -lt $HijackGraceSeconds) {
        $remaining = [math]::Round($HijackGraceSeconds - $elapsed, 1)
        Write-Host ("  `[hijack skipped - grace period (" + $remaining + "s left)`]") -ForegroundColor DarkCyan
        return
    }

    $script:LastHijack = $now

    # Minimize the foreground window
    try {
        $hwnd = [WinApi]::GetForegroundWindow()
        if ($hwnd -ne [IntPtr]::Zero) {
            [WinApi]::ShowWindow($hwnd, [WinApi]::SW_MINIMIZE) | Out-Null
            Write-Host "  `[window minimized`]" -ForegroundColor Green
        }
    } catch {
        Write-Host "  `[minimize failed: $_`]" -ForegroundColor DarkYellow
    }

    # Fling the cursor to the bottom-right corner
    try {
        $screen = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
        [WinApi]::SetCursorPos($screen.Right - 1, $screen.Bottom - 1) | Out-Null
        Write-Host "  `[cursor hijacked to bottom-right`]" -ForegroundColor Green
    } catch {
        Write-Host "  `[cursor hijack failed: $_`]" -ForegroundColor DarkYellow
    }
}

function Show-ToastNotification {
    param(
        [string]$Title,
        [string]$Message
    )

    try {
        $null = [Windows.UI.Notifications.ToastNotificationManager, Windows.UI.Notifications, ContentType = WindowsRuntime]
        $null = [Windows.Data.Xml.Dom.XmlDocument, Windows.Data.Xml.Dom.XmlDocument, ContentType = WindowsRuntime]

        $template = "<toast><visual><binding template=""ToastGeneric""><text>$Title</text><text>$Message</text></binding></visual></toast>"

        $xml = New-Object Windows.Data.Xml.Dom.XmlDocument
        $xml.LoadXml($template)

        $toast    = [Windows.UI.Notifications.ToastNotification]::new($xml)
        $notifier = [Windows.UI.Notifications.ToastNotificationManager]::CreateToastNotifier($AppId)
        $notifier.Show($toast)
        Write-Host "  `[toast sent`]" -ForegroundColor Green
        return
    } catch {
        Write-Host "  `[WinRT toast failed: $_`]" -ForegroundColor DarkYellow
    }

    try {
        $tray = New-Object System.Windows.Forms.NotifyIcon
        $tray.Icon             = [System.Drawing.SystemIcons]::Warning
        $tray.Visible          = $true
        $tray.BalloonTipTitle  = $Title
        $tray.BalloonTipText   = $Message
        $tray.BalloonTipIcon   = [System.Windows.Forms.ToolTipIcon]::Warning
        $tray.ShowBalloonTip(8000)
        Start-Sleep -Milliseconds 500
        $tray.Dispose()
        Write-Host "  `[balloon tip sent`]" -ForegroundColor Green
    } catch {
        Write-Host "  `[balloon tip also failed: $_`]" -ForegroundColor Red
    }
}

# ─── Main loop ────────────────────────────────────────────────────────────────

Write-Host "=== Watch-DistractingWindows started ===" -ForegroundColor Cyan
Write-Host "Keywords: $($Keywords -join ', ')"
Write-Host "Sound   : inline base64 -> $AlertSound (x$AlertSoundRepeats)"
Write-Host ("Polling every " + $PollIntervalSeconds + "s  |  Keyword cooldown " + $CooldownSeconds + "s  |  Hijack grace " + $HijackGraceSeconds + "s")
Write-Host "Press Ctrl+C to stop.`n"

while ($true) {
    $title = Get-ActiveWindowTitle

    if ($title) {
        foreach ($kw in $Keywords) {
            if ($title -imatch [regex]::Escape($kw)) {
                $now     = [datetime]::UtcNow
                $last    = $LastNotified[$kw]
                $elapsed = if ($last) { ($now - $last).TotalSeconds } else { [double]::MaxValue }

                if ($elapsed -ge $CooldownSeconds) {
                    $LastNotified[$kw] = $now
                    Write-Host "[$(Get-Date -Format 'HH:mm:ss')] MATCH '$kw' in: `"$title`"" -ForegroundColor Yellow

                    Invoke-Hijack
                    Show-ToastNotification -Title "Distraction: $kw" -Message $title
                    Play-AlertSound
                }
            }
        }
    }

    Start-Sleep -Seconds $PollIntervalSeconds
}

# ─── Inline sound data (base64-encoded MP3) ──────────────────────────────────
# Generate with:  .\Encode-AlertSound.ps1 "C:\path\to\alarm.mp3"
# Then paste the output between the two marker lines below.
# The script reads its own source file at startup to extract this.

#BEGIN_SOUND_BASE64

#END_SOUND_BASE64
